parameters.jsCode:
const imageRegex = /\.(jpg|jpeg|png|webp)$/i;
const keywordRegex = /Android|Samsung|Google|Galaxy/i;
// Loop over input items and add a new field called 'myNewField' to the JSON of each one
for (const item of $input.all()) {
  if(!imageRegex.test(item.json.img)){
   item.json.img = "" 
  }
  if(!keywordRegex.test(item.json.title)){
    item.json.title = ""
  }
}

return $input.all();

